"},"$:/plugins/linonetwo/health-buff-debuff-tracker/ViewTemplate/MedicineBodyChart":{"title":"$:/plugins/linonetwo/health-buff-debuff-tracker/ViewTemplate/MedicineBodyChart","echarts-refresh-trigger":"[all[tiddlers]prefix[$:/plugins/linonetwo/health-buff-debuff-tracker/medicine-checkin-log/]get[modified]]","text":"(function() {
  var logTitle = "{{{ [<logTitle>] }}}";
  var rawData = $tw.wiki.getTiddlerData(logTitle);

  var windowDays = 28;
  var counts = new Array(windowDays).fill(0);
  var days = [];
  var now = new Date();
  now.setHours(0, 0, 0, 0);

  var windowStart = new Date(now);
  windowStart.setDate(now.getDate() - (windowDays - 1));
  windowStart.setHours(0, 0, 0, 0);

  for (var i = 0; i < windowDays; i++) {
    var d = new Date(windowStart);
    d.setDate(windowStart.getDate() + i);
    days.push((d.getMonth() + 1) + '/' + d.getDate());
  }

  if (rawData && typeof rawData === "object") {
    Object.keys(rawData).forEach(function(key) {
      if (key.indexOf("daily-count") !== 0) return;
      var ts = Number(key.replace("daily-count", ""));
      if (!isFinite(ts)) return;
      var rowEnd = new Date(ts);
      rowEnd.setHours(0, 0, 0, 0);
      var rowCounts = String(rawData[key]).split(",").map(Number);
      rowCounts.forEach(function(c, index) {
        var day = new Date(rowEnd);
        day.setDate(rowEnd.getDate() - (rowCounts.length - 1 - index));
        day.setHours(0, 0, 0, 0);
        var diff = Math.round((day - windowStart) / 86400000);
        if (diff >= 0 && diff < windowDays) counts[diff] = (counts[diff] || 0) + (Number.isFinite(c) ? c : 0);
      });
    });
  }

  return {
    tooltip: { trigger: "axis" },
    grid: { left: "3%", right: "4%", bottom: "25px", top: "15px", containLabel: true },
    xAxis: {
      type: "category",
      data: days,
      axisLabel: { fontSize: 10, interval: 6 },
      boundaryGap: false
    },
    yAxis: { type: "value", minInterval: 1, splitNumber: 3 },
    series: [{
      type: "line",
      smooth: false,
      showSymbol: true,
      symbol: "circle",
      symbolSize: 8,
      data: counts,
      areaStyle: { opacity: 0.3, color: "#3b82f6" },
      lineStyle: { width: 2, color: "#3b82f6" }
    }]
  };
})()
"},"$:/plugins/linonetwo/health-buff-debuff-tracker/ViewTemplate/MedicineBodyFilter":{"title":"$:/plugins/linonetwo/health-buff-debuff-tracker/ViewTemplate/MedicineBodyFilter","tags":"$:/tags/ViewTemplateBodyFilter","list-before":"$:/config/ViewTemplateBodyFilters/default","text":"[tag[$:/tags/HealthTracker/Medicine]then[$:/plugins/linonetwo/health-buff-debuff-tracker/ViewTemplate/MedicineBody]]
